(function(){if(window.__kzGlobalDailyClaimApplied)return;window.__kzGlobalDailyClaimApplied=true;var MAX_DAYS=200;var DAY_MS=864e5;function dayStart(ts){var d=new Date(Number(ts||Date.now())||Date.now());d.setHours(0,0,0,0);return d.getTime()}function getMeSafe(){try{return typeof authGetMe==="function"?authGetMe():null}catch(e){return null}}function rawMeta(user){return user&&(user.dailyPointClaim||user.dailyClaim||user.dailyPointsClaim)||{}}function readMeta(user){var raw=rawMeta(user);return{startDay:Number(raw.startDay||0)||0,lastClaimDay:Number(raw.lastClaimDay||0)||0,totalClaimed:Number(raw.totalClaimed||0)||0,lastClaimNumber:Number(raw.lastClaimNumber||0)||0}}function getState(user){var today=dayStart(Date.now());var guest=!(user&&user.id);var meta=readMeta(user);var startDay=meta.startDay?dayStart(meta.startDay):0;var dayNumber=1;if(startDay){dayNumber=Math.floor((today-startDay)/DAY_MS)+1}if(!isFinite(dayNumber)||dayNumber<1)dayNumber=1;var finished=!!startDay&&dayNumber>MAX_DAYS;var claimedToday=!guest&&!!meta.lastClaimDay&&dayStart(meta.lastClaimDay)===today;return{guest:guest,finished:finished,claimedToday:claimedToday}}function buildClaimHtml(user){var state=getState(user);var extraClass="";var icon="fa-calendar-days";var label="Poin Harian";if(state.finished){extraClass=" is-finished";icon="fa-flag-checkered"}else if(state.claimedToday){extraClass=" is-done";icon="fa-check-circle"}else if(state.guest){icon="fa-right-to-bracket"}return'<button class="kz-balance-chip kz-daily-claim kz-daily-claim-entry'+extraClass+'" type="button" onclick="window.kzOpenDailyClaimOverlay&&window.kzOpenDailyClaimOverlay()">'+'<span class="kz-daily-claim-icon"><i class="fas '+icon+'"></i></span>'+'<span class="kz-daily-claim-btn-label">'+label+"</span>"+"</button>"}window.dailyClaimMarkup=function(user){return buildClaimHtml(user||getMeSafe()||{})};window.kzPatchHomeDailyClaim=function(){}})();


