(function(){if(window.__kzSosmedNamingFixApplied)return;window.__kzSosmedNamingFixApplied=true;function arr(v){return Array.isArray(v)?v:[]}function normSpace(s){return String(s==null?"":s).replace(/\s+/g," ").trim()}function replaceRandom(s){return normSpace(String(s==null?"":s).replace(/\bRandom\b/gi,"Luar"))}function escRe(s){return String(s).replace(/[.*+?^${}()|[\]\\]/g,"\\$&")}function simplifyPkgName(name,appName){var s=replaceRandom(name);var app=replaceRandom(appName);if(app){var appPrefix=new RegExp("^"+escRe(app)+"\\s*[\\-:|]\\s*","i");s=s.replace(appPrefix,"").trim()}if(s.indexOf("•")!==-1){s=normSpace(s.split("•").pop())}s=s.replace(/\bRandom\b/gi,"Luar").trim();s=s.replace(/\s+Luar$/i,"").trim();var qty=s.match(/\d[\d.]*\s+(Followers?|Likes?|Views?|Votes?|Stars?|Subscribers?|Subscriber|Comments?|Members?|Shares?|Saves?|Reactions?|Jam Tayang|Points?)(?:\s*\([^)]*\))?/i);if(qty)s=normSpace(qty[0]);if(!s)s=replaceRandom(name);return s}function normalizeList(list){arr(list).forEach(function(item){if(!item||!Array.isArray(item.cat)||item.cat.indexOf("sosmed")===-1)return;item.name=replaceRandom(item.name||"");if(item.badge!=null)item.badge=replaceRandom(item.badge);if(item.desc!=null)item.desc=replaceRandom(item.desc);arr(item.packages).forEach(function(pkg){if(!pkg)return;pkg.name=simplifyPkgName(pkg.name||"",item.name||"")})})}function run(){try{normalizeList(window.sosmedData)}catch(e){}try{normalizeList(window.__kzSosmedState)}catch(e){}}window.kzNormalizeSosmedNames=run;run();var oldRender=window.renderSosmedProducts;if(typeof oldRender==="function"){window.renderSosmedProducts=function(){run();return oldRender.apply(this,arguments)}}var oldInit=window.initSosmedPage;if(typeof oldInit==="function"){window.initSosmedPage=function(){run();return oldInit.apply(this,arguments)}}var oldOpen=window.openSosmedDetail;if(typeof oldOpen==="function"){window.openSosmedDetail=function(){run();return oldOpen.apply(this,arguments)}}if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",run,{once:true})}else{run()}try{window.addEventListener("pageshow",run)}catch(e){}})();


