(function(){if(window.__kzZusmoBetaOrderFixV7)return;window.__kzZusmoBetaOrderFixV7=true;function txt(v){return String(v==null?"":v).trim()}function now(){try{return authNow()}catch(e){return Date.now()}}function isZusmoProductName(name){return txt(name).toLowerCase().indexOf("zusmo beta")>=0}function isZusmoPayState(){try{if(!window.payState)return false;return isZusmoProductName(payState.product)||isZusmoProductName(payState.appName)||isZusmoProductName(payState.productRoot)||isZusmoProductName(payState.productApp)}catch(e){return false}}function normalizeData(src){src=src&&typeof src==="object"?src:{};return{uid:txt(src.uid).replace(/\D+/g,""),games:Array.isArray(src.games)?src.games.map(function(v){return txt(v)}).filter(Boolean).slice(0,2):[],platform:txt(src.platform)}}function hasData(data){data=normalizeData(data);return!!(data.uid||data.platform||data.games&&data.games.length)}function dataText(data){data=normalizeData(data);return["UID: "+(data.uid||"-"),"Game: "+(data.games&&data.games.length?data.games.join(", "):"-"),"Device: "+(data.platform||"-")].join("\n")}function cleanAdminNote(note){return txt(note).replace(/\n\n?Data Zusmo Beta:[\s\S]*$/i,"").trim()}function isZusmoOrder(order){if(!order)return false;return isZusmoProductName(order.product)||!!order.zusmoBeta}function findOrder(db,orderId){orderId=txt(orderId);if(!db||!Array.isArray(db.orders)||!orderId)return null;return db.orders.find(function(o){return o&&(txt(o.orderId)===orderId||txt(o.id)==="o_"+orderId)})||null}function mergeIntoOrder(order,rawData){if(!order)return false;var changed=false;var data=normalizeData(rawData||order.zusmoBeta||{});if(hasData(data)){var before=JSON.stringify(normalizeData(order.zusmoBeta||{}));var after=JSON.stringify(data);if(before!==after){order.zusmoBeta=data;changed=true}var req=dataText(data);if(txt(order.deliveryRequest)!==req){order.deliveryRequest=req;changed=true}var nextNote=cleanAdminNote(order.adminNote||"");nextNote=(nextNote?nextNote+"\n\n":"")+"Data Zusmo Beta:\n"+req;if(txt(order.adminNote)!==nextNote){order.adminNote=nextNote;changed=true}}var st=txt(order.status).toLowerCase();if(isZusmoOrder(order)&&!txt(order.deliveryData)&&(st==="verified"||st==="delivered")){order.status="processing";order.updatedAt=now();changed=true}return changed}function syncCurrentOrder(refreshUi){try{if(!window.payState||!payState.orderId||!isZusmoPayState())return false;var data=normalizeData(payState.zusmoBeta||{});if(!hasData(data))return false;var db=authLoadDB();var order=findOrder(db,payState.orderId);if(!order)return false;var changed=mergeIntoOrder(order,data);if(changed){authSaveDB(db);if(refreshUi){try{renderAdminAll()}catch(e){}try{renderMyOrders()}catch(e){}}}return changed}catch(e){console.warn("kz zusmo syncCurrentOrder",e);return false}}function normalizeOrders(refreshUi){try{var db=authLoadDB();if(!db||!Array.isArray(db.orders))return false;var changed=false;db.orders.forEach(function(order){if(!isZusmoOrder(order))return;if(mergeIntoOrder(order,order.zusmoBeta||{}))changed=true});if(changed){authSaveDB(db);if(refreshUi){try{renderAdminAll()}catch(e){}try{renderMyOrders()}catch(e){}}}return changed}catch(e){console.warn("kz zusmo normalizeOrders",e);return false}}if(typeof window.authCaptureFromPayState==="function"){var oldCapture=window.authCaptureFromPayState;window.authCaptureFromPayState=function(){var res=oldCapture.apply(this,arguments);setTimeout(function(){syncCurrentOrder(true)},0);return res}}document.addEventListener("click",function(ev){var btn=ev.target&&ev.target.closest?ev.target.closest("#payBtnSend"):null;if(!btn)return;setTimeout(function(){syncCurrentOrder(true)},400)},true);if(typeof window.adminSelectDeliverOrder==="function"){var oldSelect=window.adminSelectDeliverOrder;window.adminSelectDeliverOrder=function(){var res=oldSelect.apply(this,arguments);try{var db=authLoadDB();var id=txt(arguments&&arguments[0]);var order=Array.isArray(db&&db.orders)?db.orders.find(function(o){return o&&txt(o.id)===id}):null;if(order&&isZusmoOrder(order)){var noteEl=document.getElementById("adminDeliverNote");var extra=txt(order.deliveryRequest||dataText(order.zusmoBeta||{}));if(noteEl&&extra){var base=cleanAdminNote(noteEl.value||"");noteEl.value=(base?base+"\n\n":"")+"Data Zusmo Beta:\n"+extra}}}catch(e){}return res}}if(typeof window.renderMyOrders==="function"){var oldRenderMyOrders=window.renderMyOrders;window.renderMyOrders=function(){try{normalizeOrders(false)}catch(e){}return oldRenderMyOrders.apply(this,arguments)}}if(typeof window.renderAdminAll==="function"){var oldRenderAdminAll=window.renderAdminAll;window.renderAdminAll=function(){try{normalizeOrders(false)}catch(e){}return oldRenderAdminAll.apply(this,arguments)}}setTimeout(function(){normalizeOrders(true)},0);setInterval(function(){normalizeOrders(true)},15e3)})();


