/* ==== app script 90 id=kz-back-detail-no-sidebar-fix ==== */
(function(){
  if (window.__kzBackDetailNoSidebarFix) return;
  window.__kzBackDetailNoSidebarFix = true;

  function currentPage(){
    try{
      if (typeof basePage === "function") return String(basePage() || "home");
    }catch(e){}
    try{
      return String(window.__kzCurrentPage || window.__kzPrevPage || "home");
    }catch(e){}
    return "home";
  }

  function stripSidebarState(){
    try{
      var st = history.state;
      if (st && typeof st === "object" && st.kzOverlay === "sidebar") {
        history.replaceState({ kzPage: currentPage() }, "", location.href);
      }
    }catch(e){}
  }

  var prevOpenDetail = window.openDetail;
  if (typeof prevOpenDetail === "function") {
    window.openDetail = function(){
      if (!window.__kzIsPop) stripSidebarState();
      return prevOpenDetail.apply(this, arguments);
    };
  }
})();


/* ==== app script 91 id=kz-auth-entry-refresh-script ==== */
(function(){
  function ensureShell(){
    var box=document.getElementById('authFormsBox');
    if(!box||box.dataset.kzAuthEnhanced==='1') return box;
    var tabs=box.querySelector('.auth-tabs');
    var login=box.querySelector('#authLoginForm');
    var register=box.querySelector('#authRegisterForm');
    if(!tabs||!login||!register) return box;
    var shell=document.createElement('div'); shell.className='auth-entry-shell';
    var hero=document.createElement('div');
    hero.className='auth-entry-hero';
    hero.innerHTML=[
      '<div>',
      '</div>'
    ].join('');
    var panel=document.createElement('div');
    panel.className='auth-entry-panel';
    shell.appendChild(hero);
    shell.appendChild(panel);
    box.appendChild(shell);
    panel.appendChild(tabs);
    panel.appendChild(login);
    panel.appendChild(register);
    var helper=document.createElement('div');
    helper.className='auth-helper-copy';
    helper.id='authHelperCopy';
    panel.appendChild(helper);
    box.dataset.kzAuthEnhanced='1';
    return box;
  }
  function refreshAuthEntry(tab){
    var box=ensureShell();
    if(!box) return;
    var mode=tab==='register'?'register':'login';
    box.classList.toggle('is-register',mode==='register');
    var title=document.getElementById('authHeroTitle');
    var desc=document.getElementById('authHeroDesc');
    var sub=document.getElementById('authHeadSub');
    var helper=document.getElementById('authHelperCopy');
    if(title) title.textContent=mode==='register'?'Bikin akun baru yang rapi dan cepat':'Masuk lebih cepat ke akun kamu';
    if(desc) desc.textContent=mode==='register'?'Daftar sekali, lalu simpan data akun, cek pesanan, dan lanjut checkout tanpa isi ulang berulang kali.':'Pantau pesanan, simpan data, dan lanjut checkout tanpa ribet dalam satu tempat.';
    if(helper) helper.textContent=mode==='register'?'Lengkapi data dasar kamu sekali saja. Setelah itu akun siap dipakai untuk simpan identitas, cek riwayat, dan lanjut beli lebih cepat.':'Masuk untuk melanjutkan checkout, melihat detail akun, dan akses riwayat pesanan tanpa bolak-balik isi data yang sama.';
    if(sub){
      var forms=document.getElementById('authFormsBox');
      var visible=forms&&forms.style.display!=='none';
      sub.textContent=visible?(mode==='register'?'Daftar akun baru buat simpan data dan riwayat pesanan':'Masuk untuk lanjut checkout dan cek akun kamu'):sub.textContent;
    }
  }
  var oldSwitch=window.authSwitchTab;
  if(typeof oldSwitch==='function'&&!oldSwitch.__kzAuthWrapped){
    var wrapped=function(tab){var out=oldSwitch.apply(this,arguments); refreshAuthEntry(tab); return out;};
    wrapped.__kzAuthWrapped=true;
    window.authSwitchTab=wrapped;
  }
  function init(){
    ensureShell();
    var reg=document.getElementById('authRegisterForm');
    var isReg=!!(reg&&reg.style.display!=='none');
    refreshAuthEntry(isReg?'register':'login');
  }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded',init,{once:true});
  else init();
})();


