  var body=document.getElementById('modalBody');
  if(!app||!body)return;
  var list=body.querySelector('.kz-travelva-list');
  var more=body.querySelector('.kz-travelva-more-wrap');
  if(!list||!more)return;
  var items=Array.isArray(app.packages)?app.packages:[];
  if(reset){window.__kzTravelVaModalState.offset=0;list.innerHTML='';more.innerHTML=''}
  var start=Number(window.__kzTravelVaModalState.offset||0)||0;
  var step=Number(window.__kzTravelVaModalState.step||6)||6;
  var end=Math.min(start+step,items.length);
  var html='';
  for(var i=start;i<end;i++)html+=buildCard(items[i],app);
  if(start===0)list.innerHTML=html;else list.insertAdjacentHTML('beforeend',html);
  window.__kzTravelVaModalState.offset=end;
