/* ==== app script 99 id=kz-touch-feedback-pricelist-order-script ==== */
(function(){
  if(window.__kzTouchFeedbackBound)return;
  window.__kzTouchFeedbackBound=true;
  var selector='.package-card,.list-item,.btn-animated,.list-btn';
  function getTarget(node){
    return node && node.closest ? node.closest(selector) : null;
  }
  function setRipplePoint(node,ev){
    if(!node)return;
    try{
      var rect=node.getBoundingClientRect();
      var cx=rect.width/2, cy=rect.height/2;
      if(ev){
        if(typeof ev.clientX==='number' && typeof ev.clientY==='number'){
          cx=ev.clientX-rect.left;
          cy=ev.clientY-rect.top;
        }else if(ev.touches && ev.touches[0]){
          cx=ev.touches[0].clientX-rect.left;
          cy=ev.touches[0].clientY-rect.top;
        }
      }
      node.style.setProperty('--kz-ripple-x',cx+'px');
      node.style.setProperty('--kz-ripple-y',cy+'px');
    }catch(_){}
  }
  function activate(node,ev){
    if(!node)return;
    setRipplePoint(node,ev);
    try{
      node.classList.remove('kz-touch-active');
      void node.offsetWidth;
      node.classList.add('kz-touch-active');
      clearTimeout(node.__kzTouchTimer);
      node.__kzTouchTimer=setTimeout(function(){
        node.classList.remove('kz-touch-active');
      },180);
    }catch(_){}
  }
  if(window.PointerEvent){
    document.addEventListener('pointerdown',function(ev){
      var node=getTarget(ev.target);
      if(node)activate(node,ev);
    },true);
  }else{
    document.addEventListener('touchstart',function(ev){
      var node=getTarget(ev.target);
      if(node)activate(node,ev);
    },true);
    document.addEventListener('mousedown',function(ev){
      var node=getTarget(ev.target);
      if(node)activate(node,ev);
    },true);
  }
})();


